import { actionCreators, AgentPodPhase, AgentPodStatus } from '@/store/LocalDevfiles';
import { selectAgentPodStatuses } from '@/store/LocalDevfiles/selectors';

function mapPhaseToStatus(phase: AgentPodPhase, ready: boolean): DevWorkspaceStatus {
  switch (phase) {
    case AgentPodPhase.RUNNING:
      return ready ? DevWorkspaceStatus.RUNNING : DevWorkspaceStatus.STARTING;
    case AgentPodPhase.PENDING:
      return DevWorkspaceStatus.STARTING;
    case AgentPodPhase.FAILED:
    case AgentPodPhase.UNKNOWN:
      return DevWorkspaceStatus.FAILED;
    case AgentPodPhase.SUCCEEDED:
      return DevWorkspaceStatus.STOPPED;
    default:
      return DevWorkspaceStatus.STARTING;
  }
}

function AgentStatusIndicator(props: { phase: AgentPodPhase; ready: boolean }): React.ReactElement {
  const status = mapPhaseToStatus(props.phase, props.ready);
  const icon = useStatusIcon(status);
  return (
    <CheTooltip content={status.toLocaleUpperCase()}>
      <span className={statusStyles.statusIndicator} data-testid="agent-status-indicator">
        {icon}
      </span>
    </CheTooltip>
  );
}

function findAgentDefinition(
  agentId: string,
  agents: api.AiAgentDefinition[],
): api.AiAgentDefinition | undefined {
  return agents.find(a => agentId.startsWith(a.id));
}

function buildAgentTooltipContent(
  agentId: string,
  agents: api.AiAgentDefinition[],
): React.ReactElement {
  const agentDef = findAgentDefinition(agentId, agents);
  return (
    <div>
      <div>
        <strong>{agentDef?.name || 'AI Agent'}</strong>
      </div>
      {agentDef?.description && <div>{agentDef.description}</div>}
      <div style={{ marginTop: '4px', opacity: 0.7 }}>ID: {agentId}</div>
    </div>
  );
}

interface AgentPodItemProps {
  status: AgentPodStatus;
  agents: api.AiAgentDefinition[];
  onStop: (agentId: string) => void;
}

interface AgentPodItemState {
  isDropdownOpen: boolean;
  isHovered: boolean;
  isFocused: boolean;
}

class AgentPodItem extends React.PureComponent<AgentPodItemProps, AgentPodItemState> {
  constructor(props: AgentPodItemProps) {
    super(props);
    this.state = {
      isDropdownOpen: false,
      isHovered: false,
      isFocused: false,
    };
  }

  private handleStop = () => {
    this.setState({ isDropdownOpen: false });
    this.props.onStop(this.props.status.agentId);
  };

  render(): React.ReactElement {
    const { status, agents } = this.props;
    const { isDropdownOpen, isHovered, isFocused } = this.state;
    const displayName = status.name.replace(/^agent-/, '') || status.agentId;
    const isActionsVisible = isHovered || isFocused || isDropdownOpen;

    return (
      <NavItem
        className={styles.navItem}
        preventDefault={true}
        onMouseEnter={() => this.setState({ isHovered: true })}
        onMouseLeave={() => this.setState({ isHovered: false })}
        onFocus={() => this.setState({ isFocused: true })}
        onBlur={e => {
          if (!e.currentTarget.contains(e.relatedTarget as Node)) {
            this.setState({ isFocused: false });
          }
        }}
      >
        <span data-testid="agent-pod-item">
          <AgentStatusIndicator phase={status.phase} ready={status.ready} />
          <Tooltip content={buildAgentTooltipContent(status.agentId, agents)}>
            <span className={styles.titleHover}>{displayName}</span>
          </Tooltip>
        </span>
        <div
          style={{
            position: 'absolute',
            top: 0,
            right: 0,
            visibility: isActionsVisible ? 'visible' : 'hidden',
          }}
          onClick={e => e.stopPropagation()}
        >
          <Dropdown
            isOpen={isDropdownOpen}
            onOpenChange={open => this.setState({ isDropdownOpen: open })}
            toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
              <MenuToggle
                ref={toggleRef}
                variant="plain"
                onClick={() => this.setState({ isDropdownOpen: !isDropdownOpen })}
                isExpanded={isDropdownOpen}
                aria-label="Agent actions"
              >
                <EllipsisVIcon />
              </MenuToggle>
            )}
            popperProps={{ position: 'right' }}
          >
            <DropdownList>
              <DropdownItem key="stop" onClick={this.handleStop}>
                Stop
              </DropdownItem>
            </DropdownList>
          </Dropdown>
        </div>
      </NavItem>
    );
  }
}

type Props = MappedProps & {
  activePath: string;
};

export class NavigationAgentList extends React.PureComponent<Props> {
  private handleStop = (agentId: string) => {
    this.props.stopAgent(agentId);
  };

  render(): React.ReactElement {
    const { agentPodStatuses, agents } = this.props;

    if (agentPodStatuses.length === 0) {
      return <React.Fragment />;
    }

    return (
      <NavList>
        <NavGroup title="AGENT PODS" style={{ marginTop: '25px' }}>
          {agentPodStatuses.map(status => (
            <AgentPodItem
              key={status.agentId}
              status={status}
              agents={agents}
              onStop={this.handleStop}
            />
          ))}
        </NavGroup>
      </NavList>
    );
  }
}

const mapStateToProps = (state: RootState) => ({
  agentPodStatuses: selectAgentPodStatuses(state),
  agents: selectAiAgents(state),
});

const mapDispatchToProps = {
  stopAgent: actionCreators.stopAgent,
};

const connector = connect(mapStateToProps, mapDispatchToProps);
type MappedProps = ConnectedProps<typeof connector>;

export default connector(NavigationAgentList);
